use bubbletea::{Error as TeaError, Program};
use huh::{Form, FormError};
use tracing::{error, info, warn};

// Using anyhow for the main function allows mixing error types
fn main() -> anyhow::Result<()> {
    tracing_subscriber::fmt::init();

    // Example 1: Basic error propagation
    run_with_propagation()?;

    // Example 2: Pattern matching
    run_with_matching()?;

    // Example 3: Adding context
    run_with_context()?;

    Ok(())
}

/// Demonstrates simple error propagation with ?
fn run_with_propagation() -> bubbletea::Result<()> {
    let program = Program::new(MyModel::default());
    program.run()?;
    Ok(())
}

/// Demonstrates pattern matching on specific errors
fn run_with_matching() -> anyhow::Result<()> {
    let mut form = create_form();

    match form.run() {
        Ok(()) => info\!("form completed"),
        Err(FormError::UserAborted) => {
            // Not an error - user chose to cancel
            info\!("user cancelled form");
        }
        Err(FormError::Timeout(duration)) => {
            warn\!(?duration, "form timed out");
        }
        Err(FormError::Validation { field, message }) => {
            warn\!(field, message, "validation failed");
            // Could retry or show error to user
        }
        Err(e) => {
            error\!(error = %e, "form error");
            return Err(e.into());
        }
    }

    Ok(())
}

/// Demonstrates adding context with anyhow
fn run_with_context() -> anyhow::Result<()> {
    use anyhow::Context;

    let program = Program::new(MyModel::default());

    let model = program
        .run()
        .context("failed to run TUI program")?;

    info\!(result = ?model, "program completed");
    Ok(())
}

/// Helper to inspect full error chain
fn log_error_chain(error: &dyn std::error::Error) {
    error\!(error = %error, "operation failed");

    let mut depth = 1;
    let mut source = error.source();
    while let Some(cause) = source {
        error\!(depth, cause = %cause, "caused by");
        source = cause.source();
        depth += 1;
    }
}
